function maxFruits(fruits, startPos, k) {
    const n = fruits.length;
    const left = new Array(n + 1).fill(0);
    const right = new Array(n + 1).fill(0);
    let j = 0;

    for (let i = 0; i < n; i++) {
        while (j < n && fruits[j][0] - fruits[i][0] <= k) {
            right[i + 1] += fruits[j][1];
            j++;
        }
        right[i + 1] += right[i];
        if (j < n && fruits[j][0] - startPos <= k) {
            right[0] += fruits[j][1];
            j++;
        }
    }

    j = n - 1;
    for (let i = n - 1; i >= 0; i--) {
        while (j >= 0 && fruits[j][0] - fruits[i][0] <= k) {
            left[i] += fruits[j][1];
            j--;
        }
        left[i] += left[i + 1];
    }

    let ans = 0;
    for (let i = 0; i < n; i++) {
        const rest = Math.max(0, k - Math.abs(fruits[i][0] - startPos));
        const idx = fruits.findIndex((a) => a[0] >= fruits[i][0] + rest);
        ans = Math.max(ans, left[i] + right[(idx === -1) ? n : idx]);
    }

    return ans;
}
```


    1. Create left and right arrays of size n+1 filled with zeros, to store the cumulative fruits at each position.
2. Initialize a cursor j with value 0.
3. Iterate the fruits array and populate the right array with total fruits in the range of k units.
4. Then populate the left array with the remaining fruits by iterating the array in reverse order.
5. Initialize an answer variable, ans, to 0.
6. Iterate the fruits array again, calculating the remaining steps after reaching a position and using a binary search technique (in each language) to find the index of the next fruit that can be reached. Update ans with the maximum sum of fruit harvest.
7. Finally, return ans as the solution.

