import java.util.Arrays;

public int maxFruits(int[][] fruits, int startPos, int k) {
    int n = fruits.length;
    int[] left = new int[n + 1], right = new int[n + 1];
    int j = 0;

    for (int i = 0; i < n; i++) {
        while (j < n && fruits[j][0] - fruits[i][0] <= k) {
            right[i + 1] += fruits[j][1];
            j++;
        }
        right[i + 1] += right[i];
        if (j < n && fruits[j][0] - startPos <= k) {
            right[0] += fruits[j][1];
            j++;
        }
    }

    j = n - 1;
    for (int i = n - 1; i >= 0; i--) {
        while (j >= 0 && fruits[j][0] - fruits[i][0] <= k) {
            left[i] += fruits[j][1];
            j--;
        }
        left[i] += left[i + 1];
    }

    int ans = 0;
    for (int i = 0; i < n; i++) {
        int rest = Math.max(0, k - Math.abs(fruits[i][0] - startPos));
        int idx = Arrays.binarySearch(fruits, i, n, new int[]{fruits[i][0] + rest, Integer.MIN_VALUE}, (a, b) -> a[0] - b[0]);
        if (idx < 0) idx = ~idx;
        ans = Math.max(ans, left[i] + right[idx]);
    }
    return ans;
}
```


